    61                          errlist = append(errlist, err)
    62                          continue
    63                  }
    64
    65                  if ok {
    66                          return info, ok, err
    67                  }
    68          }
    69
    70          return nil, false, utilerrors.NewAggregate(errlist)
    71  }

