    32          AllServiceAccountsGroup         = "system:serviceaccounts"
    33          // IssuedCredentialIDAuditAnnotationKey is the annotation key used in the audit event that is persisted to the
    34          // '/token' endpoint for service accounts.
    35          // This annotation indicates the generated credential identifier for the service account token being issued.
    36          // This is useful when tracing back the origin of tokens that have gone on to make request that have persisted
    37          // their credential-identifier into the audit log via the user's extra info stored on subsequent audit events.
    38          IssuedCredentialIDAuditAnnotationKey = "authentication.kubernetes.io/issued-credential-id"
