    53  // MakeUsername generates a username from the given namespace and ServiceAccount name.
    54  // The resulting username can be passed to SplitUsername to extract the original namespace and ServiceAccount name.
    55  func MakeUsername(namespace, name string) string {
    56          return ServiceAccountUsernamePrefix + namespace + ServiceAccountUsernameSeparator + name
    57  }
    58
    59  // MatchesUsername checks whether the provided username matches the namespace and name without
    60  // allocating. Use this when checking a service account namespace and name against a known string.
    61  func MatchesUsername(namespace, name string, username string) bool {
    62          if !strings.HasPrefix(username, ServiceAccountUsernamePrefix) {
    63                  return false
    64          }
    65          username = username[len(ServiceAccountUsernamePrefix):]
    66
    67          if !strings.HasPrefix(username, namespace) {
    68                  return false
    69          }
    70          username = username[len(namespace):]
    71
    72          if !strings.HasPrefix(username, ServiceAccountUsernameSeparator) {
    73                  return false
    74          }
    75          username = username[len(ServiceAccountUsernameSeparator):]
    76
    77          return username == name
    78  }
    79
    80  var invalidUsernameErr = fmt.Errorf("Username must be in the form %s", MakeUsername("namespace", "name"))
    81
    82  // SplitUsername returns the namespace and ServiceAccount name embedded in the given username,
    83  // or an error if the username is not a valid name produced by MakeUsername
    84  func SplitUsername(username string) (string, string, error) {
    85          if !strings.HasPrefix(username, ServiceAccountUsernamePrefix) {
    86                  return "", "", invalidUsernameErr
    87          }
    88          trimmed := strings.TrimPrefix(username, ServiceAccountUsernamePrefix)
    89          parts := strings.Split(trimmed, ServiceAccountUsernameSeparator)
    90          if len(parts) != 2 {
    91                  return "", "", invalidUsernameErr
    92          }
    93          namespace, name := parts[0], parts[1]
    94          if len(apimachineryvalidation.ValidateNamespaceName(namespace, false)) != 0 {
    95                  return "", "", invalidUsernameErr
    96          }
    97          if len(apimachineryvalidation.ValidateServiceAccountName(name, false)) != 0 {
    98                  return "", "", invalidUsernameErr
    99          }
   100          return namespace, name, nil
   101  }
