   103  // MakeGroupNames generates service account group names for the given namespace
   104  func MakeGroupNames(namespace string) []string {
   105          return []string{
   106                  AllServiceAccountsGroup,
   107                  MakeNamespaceGroupName(namespace),
   108          }
   109  }
   110
   111  // MakeNamespaceGroupName returns the name of the group all service accounts in the namespace are included in
   112  func MakeNamespaceGroupName(namespace string) string {
   113          return ServiceAccountGroupPrefix + namespace
   114  }
