   116  // UserInfo returns a user.Info interface for the given namespace, service account name and UID
   117  func UserInfo(namespace, name, uid string) user.Info {
   118          return (&ServiceAccountInfo{
   119                  Name:      name,
   120                  Namespace: namespace,
   121                  UID:       uid,
   122          }).UserInfo()
   123  }
