   125  type ServiceAccountInfo struct {
   126          Name, Namespace, UID string
   127          PodName, PodUID      string
   128          CredentialID         string
   129          NodeName, NodeUID    string
   130  }
   131
   132  func (sa *ServiceAccountInfo) UserInfo() user.Info {
   133          info := &user.DefaultInfo{
   134                  Name:   MakeUsername(sa.Namespace, sa.Name),
   135                  UID:    sa.UID,
   136                  Groups: MakeGroupNames(sa.Namespace),
   137          }
   138
   139          if sa.PodName != "" && sa.PodUID != "" {
   140                  if info.Extra == nil {
   141                          info.Extra = make(map[string][]string)
   142                  }
   143                  info.Extra[PodNameKey] = []string{sa.PodName}
   144                  info.Extra[PodUIDKey] = []string{sa.PodUID}
   145          }
   146          if sa.CredentialID != "" {
   147                  if info.Extra == nil {
   148                          info.Extra = make(map[string][]string)
   149                  }
   150                  info.Extra[user.CredentialIDKey] = []string{sa.CredentialID}
   151          }
   152          if sa.NodeName != "" {
   153                  if info.Extra == nil {
   154                          info.Extra = make(map[string][]string)
   155                  }
   156                  info.Extra[NodeNameKey] = []string{sa.NodeName}
   157                  // node UID is optional and will only be set if the node name is set
   158                  if sa.NodeUID != "" {
   159                          info.Extra[NodeUIDKey] = []string{sa.NodeUID}
   160                  }
   161          }
   162
   163          return info
   164  }
