   166  // IsServiceAccountToken returns true if the secret is a valid api token for the service account
   167  func IsServiceAccountToken(secret *v1.Secret, sa *v1.ServiceAccount) bool {
   168          if secret.Type != v1.SecretTypeServiceAccountToken {
   169                  return false
   170          }
   171
   172          name := secret.Annotations[v1.ServiceAccountNameKey]
   173          uid := secret.Annotations[v1.ServiceAccountUIDKey]
   174          if name != sa.Name {
   175                  // Name must match
   176                  return false
   177          }
   178          if len(uid) > 0 && uid != string(sa.UID) {
   179                  // If UID is specified, it must match
   180                  return false
   181          }
   182
   183          return true
   184  }

